/// <summary>
/// Represents a published article or blog post.
/// </summary>
[Description("Represents a published article or blog post.")]
public record Article
{
    [Key]
    [Description("URL-friendly slug for the article")]
    public string Url { get; init; } = string.Empty;

    [Description("Title of the article")]
    public string? Title { get; init; }

    [Description("Main content in markdown format")]
    public string Content { get; init; } = string.Empty;

    [Description("Publication status (Draft, Published, Archived)")]
    public ArticleStatus Status { get; init; } = ArticleStatus.Draft;

    [Description("Date and time when the article was published")]
    public DateTime? Published { get; init; }

    [Description("URL for the article thumbnail image")]
    public string? Thumbnail { get; init; }

    [Description("Number of times the article has been viewed")]
    public int Views { get; init; }

    [Description("Number of likes or reactions")]
    public int Likes { get; init; }

    [Description("Number of comments on the article")]
    public int Comments { get; init; }

    [Description("List of tags for categorization")]
    public List<string>? Tags { get; init; }

    [Description("List of author identifiers")]
    public List<string>? Authors { get; init; }
}

[Description("Publication status of an article")]
public enum ArticleStatus
{
    [Description("Article is in draft mode")]
    Draft,
    [Description("Article is publicly published")]
    Published,
    [Description("Article is archived and no longer visible")]
    Archived
}
